import{_ as e,c as a,a0 as o,o as r}from"./chunks/framework.BGabeMLJ.js";const s="/images/node_ui_images/data_store_creator.png",i="/images/node_ui_images/datastore_manager.png",m=JSON.parse('{"title":"Data Store Management","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/data-store-management.md","filePath":"guide/admin/data-store-management.md"}'),n={name:"guide/admin/data-store-management.md"};function d(c,t,l,h,u,p){return r(),a("div",null,t[0]||(t[0]=[o('<h1 id="data-store-management" tabindex="-1">Data Store Management <a class="header-anchor" href="#data-store-management" aria-label="Permalink to &quot;Data Store Management&quot;">â€‹</a></h1><p>Before an analysis can be run, its associated project must be allowed to access the required data at the institution. To achieve this, either an administrator or data steward needs to create <strong>data stores</strong>. These are the configuration settings that map individual projects to the directories containing the requested data on the organization&#39;s servers.</p><h2 id="creating-a-data-store" tabindex="-1">Creating a Data Store <a class="header-anchor" href="#creating-a-data-store" aria-label="Permalink to &quot;Creating a Data Store&quot;">â€‹</a></h2><p>Navigate to the Data Store Creation tool by clicking on &quot;Data Stores&quot; -&gt; &quot;Create&quot; in the menu bar at the top of the page. You should see a partially filled out table:</p><p><a href="/images/node_ui_images/data_store_creator.png"><img src="'+s+'" alt="Data Store Creator"></a></p><p>Simply fill out the required information in the table and click &quot;Submit&quot; under the table. If everything worked correctly, a green box will appear in the top right of the page indicating a data store was successfully created. If not, a red box will appear with a suggestion as to what may be wrong. If this occurs, please verify the provided values in the table or contact support for help.</p><div class="tip custom-block"><p class="custom-block-title">Private S3 Buckets</p><p>For more information on how to generate the required keys for private S3 buckets, visit <a href="./bucket-setup-for-data-store.html">Bucket Setup for Data Store</a></p></div><p>A description of the fields in the table can be found below.</p><h3 id="field-descriptions" tabindex="-1">Field Descriptions <a class="header-anchor" href="#field-descriptions" aria-label="Permalink to &quot;Field Descriptions&quot;">â€‹</a></h3><table tabindex="0"><thead><tr><th><strong>Field</strong></th><th><strong>Description</strong></th></tr></thead><tbody><tr><td>Project</td><td>Select from the currently approved list of projects for your node</td></tr><tr><td>Data Store</td><td>This field is automatically populated using the UUID of the selected project. This identifier is used as the name of the data store when it is created in the node software</td></tr><tr><td>Data Store Type</td><td>Type of repository in which the data is stored. Currently, only FHIR and S3 are supported</td></tr><tr><td>Data Path (FHIR only)</td><td>The absolute directory path where the requested data is located</td></tr><tr><td>Bucket Name (S3 only)</td><td>The name of the S3 bucket in which the data is located</td></tr><tr><td>Bucket Access (S3 only)</td><td>Whether the S3 bucket is &quot;Private&quot; or &quot;Public&quot;. It is highly recommended to keep all S3 buckets set to private</td></tr><tr><td>Access Key (S3 only)</td><td>Generated access key used for accessing the listed, private S3 bucket</td></tr><tr><td>Secret Key (S3 only)</td><td>Generated secret key used for accessing the listed, private S3 bucket</td></tr><tr><td>Hostname</td><td>Name of the server on which the data is located</td></tr><tr><td>Port</td><td>Connection endpoint for accessing the server. Use 80 for HTTP and 443 for HTTPS. If a different protocol is used, please verify which port is accessible</td></tr><tr><td>Protocol</td><td>Protocol used for transferring files</td></tr></tbody></table><h2 id="managing-data-access" tabindex="-1">Managing Data Access <a class="header-anchor" href="#managing-data-access" aria-label="Permalink to &quot;Managing Data Access&quot;">â€‹</a></h2><p>If a project is no longer approved, valid, or has been terminated, then the associated data stores should be removed. The Node UI provides an interface for both disconnecting individual analyses from accessing the requested data and permanently deleting data stores.</p><p>To manage previously created data stores as well as analysis data access, navigate to the Data Store Management page by clicking on &quot;Data Stores&quot; -&gt; &quot;Manage&quot; in the menu bar at the top of the Node UI to access an overview table of the current data stores (see <a href="#field-descriptions">Field Descriptions</a> for descriptions of the columns).</p><p>Each listed data store in this table also has a button for testing the connection to the mapped server in the &quot;Test&quot; column. If a user reports that they are unable to access the requested data, you can use this button to check whether the connection is still valid. If it is no longer valid, for example because a security setting or port was changed, the data store should be deleted and recreated.</p><p><a href="/images/node_ui_images/datastore_manager.png"><img src="'+i+'" alt="Data Store Manager"></a></p><h3 id="deleting-a-data-store" tabindex="-1">Deleting a Data Store <a class="header-anchor" href="#deleting-a-data-store" aria-label="Permalink to &quot;Deleting a Data Store&quot;">â€‹</a></h3><p>The final column has a button for deleting the data store in that row. Simply click the button and confirm that you want to delete the data store, thereby removing all access to the associated data.</p><div class="warning custom-block"><p class="custom-block-title">Stopping the Analyses</p><p>Deleting a data store also immediately disconnects all analyses and projects from the data. Be sure the analyses have either all run to completion or the users have been notified.</p></div>',18)]))}const f=e(n,[["render",d]]);export{m as __pageData,f as default};
